/**
 * @generated by @flusk/cli — customized
 * TUI Screen: Overview — cost summary + top patterns + live feed
 */

import React from 'react';
// @ts-ignore ink types use exports field
import { Box, Text } from 'ink';
import { useApi } from '../hooks/use-api.js';
import { useLiveFeed } from '../hooks/use-live-feed.js';
import { CostSummary } from '../components/cost-summary.js';
import type { CostData } from '../components/cost-summary.js';
import { PatternList } from '../components/pattern-list.js';
import type { Pattern } from '../components/pattern-list.js';
import { LiveFeed } from '../components/live-feed.js';

export interface OverviewScreenProps {
  endpoint: string;
  apiKey: string;
}

export function OverviewScreen({ endpoint, apiKey }: OverviewScreenProps) {
  const costs = useApi<CostData>(endpoint, '/api/v1/costs/summary', apiKey);
  const patterns = useApi<Pattern[]>(endpoint, '/api/v1/patterns', apiKey);
  const events = useLiveFeed(endpoint);

  if (costs.loading) return <Text>Loading overview...</Text>;
  if (costs.error) return <Text color="red">Error: {costs.error}</Text>;

  return (
    <Box flexDirection="column">
      <CostSummary data={costs.data} />
      <PatternList patterns={patterns.data || []} limit={5} />
      <Box marginTop={1}>
        <LiveFeed events={events} limit={5} />
      </Box>
    </Box>
  );
}
